document.addEventListener("DOMContentLoaded",function(){let e=window.dashboardData||{},t=e.ageLabels,n=e.ageCounts,s=document.getElementById("ageGroupChart");if(s&&t&&t.length&&n&&n.length){let r=s.getContext("2d");new Chart(r,{type:"doughnut",data:{labels:t,datasets:[{label:"Population by Age Group",data:n,backgroundColor:["rgba(54, 162, 235, 0.8)","rgba(255, 206, 86, 0.8)","rgba(75, 192, 192, 0.8)","rgba(153, 102, 255, 0.8)","rgba(255, 99, 132, 0.8)"],borderColor:"#fff",borderWidth:2}]},options:{responsive:!0,maintainAspectRatio:!1,plugins:{legend:{position:"top"},tooltip:{callbacks:{label:function(e){let t=e.label||"";return t&&(t+=": "),null!==e.parsed&&(t+=e.parsed),t}}}}}})}let o=e.residentsMonths,a=e.residentsCounts,i=document.getElementById("residentsPerMonthChart");if(i&&o&&o.length&&a&&a.length){let l=i.getContext("2d");new Chart(l,{type:"bar",data:{labels:o,datasets:[{label:"Residents Added",data:a,backgroundColor:"rgba(54, 162, 235, 0.7)",borderColor:"rgba(54, 162, 235, 1)",borderWidth:1,maxBarThickness:40}]},options:{responsive:!0,maintainAspectRatio:!1,scales:{y:{beginAtZero:!0,ticks:{stepSize:1}}}}})}let d=e.businessMonths,c=e.businessCounts,m=document.getElementById("businessesPerMonthChart");if(m&&d&&d.length&&c&&c.length){let u=m.getContext("2d");new Chart(u,{type:"bar",data:{labels:d,datasets:[{label:"Businesses Added",data:c,backgroundColor:"rgba(16, 185, 129, 0.7)",borderColor:"rgba(16, 185, 129, 1)",borderWidth:1,maxBarThickness:40}]},options:{responsive:!0,maintainAspectRatio:!1,scales:{y:{beginAtZero:!0,ticks:{stepSize:1}}}}})}});
function setTextIfPresent(e,t){let n=document.getElementById(e);n&&(n.textContent=t)}
function updateDashboardStats(){fetch("partials/dashboard-stats.php").then(e=>e.json()).then(e=>{setTextIfPresent("pending-requests-count",e.pending_requests),setTextIfPresent("business-count",e.business_count),setTextIfPresent("population-count",e.resident_count),setTextIfPresent("active-incidents-count",e.active_incidents),setTextIfPresent("upcoming-events-count",e.upcoming_events)}).catch(()=>{})}
setInterval(updateDashboardStats,5e3),updateDashboardStats();
function getTimeSegmentElements(e){let t=e.querySelector(".segment-display"),n=e.querySelector(".segment-overlay");if(!t||!n)return null;return{segmentDisplayTop:t.querySelector(".segment-display__top"),segmentDisplayBottom:t.querySelector(".segment-display__bottom"),segmentOverlay:n,segmentOverlayTop:n.querySelector(".segment-overlay__top"),segmentOverlayBottom:n.querySelector(".segment-overlay__bottom")}}
function updateSegmentValues(e,t,n){e&&(e.textContent=n),t&&(t.textContent=n)}
function updateTimeSegment(e,t){let n=getTimeSegmentElements(e);if(!n||!n.segmentDisplayTop||!n.segmentDisplayBottom||!n.segmentOverlay||!n.segmentOverlayTop||!n.segmentOverlayBottom)return;if(parseInt(n.segmentDisplayTop.textContent,10)===t)return;n.segmentOverlay.classList.add("flip"),updateSegmentValues(n.segmentDisplayTop,n.segmentOverlayBottom,t);function s(){n.segmentOverlay.classList.remove("flip"),updateSegmentValues(n.segmentDisplayBottom,n.segmentOverlayTop,t),this.removeEventListener("animationend",s)}n.segmentOverlay.addEventListener("animationend",s)}
function updateTimeSection(e,t){let n=Math.floor(t/10)||0,s=t%10||0,r=document.getElementById(e);if(!r)return;let o=r.querySelectorAll(".time-segment");o.length>=2&&(updateTimeSegment(o[0],n),updateTimeSegment(o[1],s))}
function updateCurrentTime(){let e=new Date,t=e.getHours(),n=e.getMinutes(),s=e.getSeconds();t=(t%=12)?t:12,updateTimeSection("hours",t),updateTimeSection("minutes",n),updateTimeSection("seconds",s);let r=document.getElementById("current-date");r&&(r.textContent=e.toLocaleDateString("en-US",{weekday:"long",year:"numeric",month:"long",day:"numeric"}))}
document.addEventListener("DOMContentLoaded",function(){updateCurrentTime(),setInterval(updateCurrentTime,1e3)});
